import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"创新分与人文分","description":"什么是创新分，创新分有什么用，如何获得创新分。本文章以电力学院为例","frontmatter":{"lang":"zh-CN","title":"创新分与人文分","description":"什么是创新分，创新分有什么用，如何获得创新分。本文章以电力学院为例"},"headers":[],"relativePath":"en/learn/extra/innovation_humanities_scores.md","filePath":"en/learn/extra/innovation_humanities_scores.md","lastUpdated":1784220723000}`),a={name:`en/learn/extra/innovation_humanities_scores.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/extra/innovation_humanities_scores.md for this page in Markdown format</div><h1 id="关于创新分与人文分的要求" tabindex="-1">关于创新分与人文分的要求 <a class="header-anchor" href="#关于创新分与人文分的要求" aria-label="Permalink to “关于创新分与人文分的要求”">​</a></h1><p><em>注意：本文章参考的文献与规定均来自电力学院2025年规定，内容具有时效性与院间差异性，参考本文内容时请注意与你所在学院的差异。</em></p><h2 id="创新分" tabindex="-1">创新分 <a class="header-anchor" href="#创新分" aria-label="Permalink to “创新分”">​</a></h2><p>毕业要求4分</p><p><strong>获取渠道</strong></p><h3 id="_1-学校或本学院的讲座票" tabindex="-1">1. 学校或本学院的讲座票 <a class="header-anchor" href="#_1-学校或本学院的讲座票" aria-label="Permalink to “1. 学校或本学院的讲座票”">​</a></h3><p>分数：一般为0.2分/张 证明材料：讲座票原件 评价：难度低，可黑市收 注意：一般不认其它学院的；部分学院有要求上限不超过2分；讲座票一定为原件，须妥善保存四年</p><h3 id="_2-科研活动-包括srp、百步梯攀登计划等" tabindex="-1">2. 科研活动（包括srp、百步梯攀登计划等） <a class="header-anchor" href="#_2-科研活动-包括srp、百步梯攀登计划等" aria-label="Permalink to “2. 科研活动（包括srp、百步梯攀登计划等）”">​</a></h3><p>分数：一学期2分；一学年4分 证明材料：校级看系统，院级由导师开具纸质证明 评价：看导师情况决定性价比，部分srp同时能提供竞赛机会 注意：并非只有系统上的项目可加分，部分老师有院级srp项目，建议询问本学院学长获取相关资讯，主动联系老师。</p><h3 id="_3-学科竞赛与科技竞赛" tabindex="-1">3. 学科竞赛与科技竞赛 <a class="header-anchor" href="#_3-学科竞赛与科技竞赛" aria-label="Permalink to “3. 学科竞赛与科技竞赛”">​</a></h3><p>分数：只参赛但没获奖加 0.5分，若有获奖，可加 1 分；同一比赛不同级别，可累加分数。 证明材料：主办方开具参赛证明；获奖证明 评价：性价比较高；学有余力可多参与</p><h3 id="_4-论文与专利" tabindex="-1">4. 论文与专利 <a class="header-anchor" href="#_4-论文与专利" aria-label="Permalink to “4. 论文与专利”">​</a></h3><p>见表格（附件，待施工）</p><h2 id="人文分" tabindex="-1">人文分 <a class="header-anchor" href="#人文分" aria-label="Permalink to “人文分”">​</a></h2><p>毕业要求2分（1.5+0.5） 其中参与文艺活动获得1.5分；i志愿志愿时满30h获得0.5分（该部分不可用其它分数代替）</p><p><strong>获取渠道</strong></p><h3 id="_1-各类人文类型的讲座票" tabindex="-1">1. 各类人文类型的讲座票 <a class="header-anchor" href="#_1-各类人文类型的讲座票" aria-label="Permalink to “1. 各类人文类型的讲座票”">​</a></h3><p>分数：以讲座票为准 证明材料：为讲座票（需盖公章） 注意：入场券不计分；主办方为外院或者某协会的无效</p><h3 id="_2-各类文体竞赛" tabindex="-1">2. 各类文体竞赛 <a class="header-anchor" href="#_2-各类文体竞赛" aria-label="Permalink to “2. 各类文体竞赛”">​</a></h3><p>分数：0.5分/次 证明材料：仅参赛但没获奖的由竞赛主办单位或承办单位开具证明材料；有获奖的则以获奖证书复印件作为证明材料</p><h3 id="_3-校运会、院运会" tabindex="-1">3. 校运会、院运会， <a class="header-anchor" href="#_3-校运会、院运会" aria-label="Permalink to “3. 校运会、院运会，”">​</a></h3><p>分数：按 0.5分/年 （参加一次院运会加 0.5分，多个项目不叠加）。 证明材料：学院团学出具证明材料</p><h3 id="_4-院运会方阵" tabindex="-1">4. 院运会方阵 <a class="header-anchor" href="#_4-院运会方阵" aria-label="Permalink to “4. 院运会方阵”">​</a></h3><p>分数：0.5 分（四年只加一次） 证明材料：由各班出具名单，然后自行联系院学生会体育部制作证明材料 注意：校运会开幕式闭幕式观众不予加分</p><h3 id="_5-院级篮球赛、足球赛等各类型比赛" tabindex="-1">5. 院级篮球赛、足球赛等各类型比赛 <a class="header-anchor" href="#_5-院级篮球赛、足球赛等各类型比赛" aria-label="Permalink to “5. 院级篮球赛、足球赛等各类型比赛”">​</a></h3><p>分数：0.5 分（四年只加一次） 证明材料：由各班出具名单，然后自行联系院学生会体育部制作证明材料， 注意：不同项目可叠加</p><h3 id="_6-各类型院队、校队运动员" tabindex="-1">6. 各类型院队、校队运动员 <a class="header-anchor" href="#_6-各类型院队、校队运动员" aria-label="Permalink to “6. 各类型院队、校队运动员”">​</a></h3><p>分数：0.5分（四年只加一次） 证明材料：由团学提供</p><h3 id="_7-学院组织的迎新晚会、才艺之星文娱活动" tabindex="-1">7. 学院组织的迎新晚会、才艺之星文娱活动 <a class="header-anchor" href="#_7-学院组织的迎新晚会、才艺之星文娱活动" aria-label="Permalink to “7. 学院组织的迎新晚会、才艺之星文娱活动”">​</a></h3><p>可加 0.5分（人文） ，证明材料由团学提供。</p><h3 id="_8-党校党支部组织的参观活动" tabindex="-1">8. 党校党支部组织的参观活动 <a class="header-anchor" href="#_8-党校党支部组织的参观活动" aria-label="Permalink to “8. 党校党支部组织的参观活动”">​</a></h3><p>有创新学分、人文学分加分条的才能加。</p>`,33)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};